#include <stdio.h>

int main(void)
{
    int r, g, bb;
    long long int a, b, c;

    for (;;) {
        if (scanf(" %d %d %d", &r, &g, &bb) != 3)
            return 0;
        if (r >= g && r >= bb) {
            a = r;
            if (g >= bb) {
                b = g;
                c = bb;
            } else {
                b = bb;
                c = g;
            }
        } else if (g >= bb) {
            a = g;
            if (r >= bb) {
                b = r;
                c = bb;
            } else {
                b = bb;
                c = r;
            }
        } else {
            a = bb;
            if (r >= g) {
                b = r;
                c = g;
            } else {
                b = g;
                c = r;
            }
        }
        if (a >= ((b + c) * 2)) {
            printf("%ld\n", (long int)(b+c));
        } else {
            printf("%ld\n", (long int)( c + ((a - c) + (b - c)) / 3) );
        }
    }

    return 0;

}

