use std::io;

macro_rules! parse_line {
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        io::stdin().read_line(&mut a_str).unwrap();
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    })
}

fn main() {
    let (mut r, mut g, mut b) = parse_line!(u64, u64, u64);
    if r > g {
        std::mem::swap(&mut r, &mut g)
    }
    if g > b {
        std::mem::swap(&mut g, &mut b)
    }
    let s = r + g + b;
    let v = r + g;
    println!("{:?}", if s / 3 < v { s / 3 } else { v });
}
